SELECT volunActTitle, finVolunActProcEnd FROM ( SELECT Volun_Act_Title AS volunActTitle, DATE_FORMAT(Volun_Act_Date, '%Y-%m-%d') AS finVolunActProcEnd, Volun_Act_Date AS sortDate FROM TBL_VOLUN_HISTORY WHERE User_No = #{userNo}
UNION ALL
SELECT tvac.VOLUN_ACT_TITLE AS volunActTitle, DATE_FORMAT(tvac.VOLUN_ACT_PROC_END, '%Y-%m-%d') AS finVolunActProcEnd, tvac.VOLUN_ACT_PROC_END AS sortDate FROM TBL_VOLUN_APPLY tvapp JOIN TBL_VOLUN_ACTIVITY tvac ON tvapp.VOLUN_ACT_NO = tvac.VOLUN_ACT_NO WHERE tvapp.USER_NO = #{userNo} AND tvac.VOLUN_ACT_PROC_END < NOW() ) A ORDER BY sortDate DESC LIMIT 1

