mapper.select:
SELECT *
FROM (
    SELECT
        log_reason AS logReason,
        DATE_FORMAT(LOG_DATE, '%Y.%m.%d') AS logDate,
        change_amount AS changeAmount,
        @rownum := @rownum + 1 AS rn
    FROM TBL_LOG_POINT, (SELECT @rownum := 0) r
    WHERE USER_NO = #{userNo}
      AND CHANGE_AMOUNT > 0
    ORDER BY LOG_NO DESC
) t
WHERE t.rn BETWEEN #{startRow} AND #{endRow}

